import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

const categoryColors = {
  Languages: "var(--accent)",
  Frameworks: "var(--accent2)",
  Tools: "var(--accent3)",
  Databases: "#34d399",
  Concepts: "#f472b6",
};

export function SectionLabel({ text }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4 }}
      viewport={{ once: true }}
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: 8,
        marginBottom: "0.75rem",
      }}
    >
      <span style={{ width: 22, height: 1, background: "var(--accent)" }} />
      <span
        style={{
          fontSize: "0.7rem",
          color: "var(--accent)",
          fontFamily: "var(--font-display)",
          fontWeight: 700,
          letterSpacing: "0.12em",
          textTransform: "uppercase",
        }}
      >
        {text}
      </span>
    </motion.div>
  );
}

export const sectionTitle = {
  fontFamily: "var(--font-display)",
  fontWeight: 800,
  fontSize: "clamp(1.6rem, 3.5vw, 2.5rem)",
  letterSpacing: "-0.02em",
  marginBottom: "1.75rem",
  lineHeight: 1.1,
};

export default function Skills({ skills }) {
  const categories = Object.keys(skills || {});
  const [active, setActive] = useState(categories[0] || "");

  if (!skills || categories.length === 0) return null;

  return (
    <>
      <style>{`
        /* ── Section wrapper — mirrors Work Experience padding exactly ── */
        .skills-section {
          padding: clamp(2.5rem, 6vw, 5rem) clamp(1.25rem, 5vw, 4rem);
          max-width: 1400px;          /* same cap as sibling sections */
          margin: 0 auto;             /* centre on ultra-wide */
          box-sizing: border-box;
          width: 100%;
        }

        /* ── Category tabs ── */
        .skill-tabs {
          display: flex;
          gap: 0.5rem;
          flex-wrap: wrap;
          margin-bottom: 2rem;
        }

        .skill-tab {
          padding: 8px 18px;
          border-radius: 999px;
          border: 1px solid var(--border);
          font-family: var(--font-display);
          font-weight: 600;
          font-size: clamp(0.72rem, 1vw, 0.88rem);
          cursor: pointer;
          transition: all 0.25s ease;
          white-space: nowrap;
          background: transparent;
        }

        .skill-tab:hover {
          transform: translateY(-2px);
        }

        /* ── Chip grid ──
             Each chip is exactly the same height (fixed) and the same
             width (equal columns).  Text that is too long wraps inside
             the fixed-height box — no chip ever grows taller than its
             neighbours because we use align-items: center + fixed height.
        ── */
        .skill-chips {
          display: grid;
          gap: 0.85rem;
          /* 5 columns on large screens, scales down gracefully */
          grid-template-columns: repeat(5, 1fr);
        }

        .skill-chip {
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 6px;
          text-align: center;
          /* Fixed height so every card is identical */
          min-height: 56px;
          padding: 0 12px;
          border-radius: 12px;
          background: var(--surface2);
          border: 1px solid var(--border);
          font-size: clamp(0.78rem, 0.9vw, 0.9rem);
          font-family: var(--font-display);
          font-weight: 500;
          transition: all 0.3s ease;
          word-break: break-word;
          hyphens: auto;
          /* Prevent the grid cell from shrinking below equal width */
          min-width: 0;
          box-sizing: border-box;
        }

        .skill-chip:hover {
          transform: translateY(-5px) scale(1.04);
          box-shadow: 0 8px 24px rgba(0, 0, 0, 0.2);
        }

        /* ── Responsive breakpoints ── */

        /* Large tablet / small laptop  →  4 columns */
        @media (max-width: 1024px) {
          .skill-chips {
            grid-template-columns: repeat(4, 1fr);
          }
        }

        /* Tablet  →  3 columns */
        @media (max-width: 768px) {
          .skill-chips {
            grid-template-columns: repeat(3, 1fr);
          }
          .skill-chip {
            min-height: 52px;
          }
        }

        /* Large phone  →  2 columns */
        @media (max-width: 480px) {
          .skill-chips {
            grid-template-columns: repeat(2, 1fr);
            gap: 0.65rem;
          }
          .skill-chip {
            min-height: 50px;
            font-size: 0.8rem;
          }
        }
      `}</style>

      <section className="skills-section" id="skills">
        <SectionLabel text="Expertise" />

        <motion.h2
          style={sectionTitle}
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
        >
          Technical Skills
        </motion.h2>

        {/* Category Tabs */}
        <div className="skill-tabs">
          {categories.map((cat) => (
            <motion.button
              key={cat}
              className="skill-tab"
              onClick={() => setActive(cat)}
              whileTap={{ scale: 0.95 }}
              animate={{
                borderColor:
                  active === cat ? categoryColors[cat] : "var(--border)",
                background:
                  active === cat
                    ? `${categoryColors[cat]}18`
                    : "transparent",
                color:
                  active === cat ? categoryColors[cat] : "var(--muted)",
              }}
            >
              {cat}
            </motion.button>
          ))}
        </div>

        {/* Skill Chips — equal-size grid */}
        <motion.div layout className="skill-chips">
          <AnimatePresence>
            {skills?.[active]?.map((skill, i) => (
              <motion.div
                key={skill}
                className="skill-chip"
                initial={{ opacity: 0, y: 20, scale: 0.9 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                exit={{ opacity: 0, scale: 0.9 }}
                transition={{ delay: i * 0.05 }}
                style={{
                  borderColor: `${categoryColors[active]}40`,
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.borderColor = categoryColors[active];
                  e.currentTarget.style.background = `${categoryColors[active]}15`;
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.borderColor = `${categoryColors[active]}40`;
                  e.currentTarget.style.background = "var(--surface2)";
                }}
              >
                <span
                  style={{
                    color: categoryColors[active],
                    flexShrink: 0,
                    fontSize: "0.75rem",
                  }}
                >
                  ▸
                </span>
                {skill}
              </motion.div>
            ))}
          </AnimatePresence>
        </motion.div>
      </section>
    </>
  );
}
